package evidence

import (
	"strings"
	"testing"
)

const sampleDiff = `diff --git a/foo.go b/foo.go
index abc..def 100644
--- a/foo.go
+++ b/foo.go
@@ -1,3 +1,4 @@
 line1
+added
 line2
 line3
diff --git a/bar.go b/bar.go
index 111..222 100644
--- a/bar.go
+++ b/bar.go
@@ -10,2 +10,3 @@
 x
+y
 z
`

func TestDecomposeDiff(t *testing.T) {
	files := DecomposeDiff(sampleDiff)
	if len(files) != 2 {
		t.Fatalf("got %d files, want 2", len(files))
	}
	if files[0].Path != "foo.go" {
		t.Errorf("file 0 path = %q", files[0].Path)
	}
	if len(files[0].HunkHeaders) != 1 {
		t.Errorf("file 0 hunk count = %d", len(files[0].HunkHeaders))
	}
	if files[1].Path != "bar.go" {
		t.Errorf("file 1 path = %q", files[1].Path)
	}
}

func TestClampDiffWithinBudget(t *testing.T) {
	out, sec := ClampDiff(sampleDiff, len(sampleDiff)+10)
	if out != sampleDiff {
		t.Errorf("expected unchanged")
	}
	if sec.TruncationReason != "" {
		t.Errorf("unexpected truncation: %q", sec.TruncationReason)
	}
}

func TestClampDiffDegrades(t *testing.T) {
	// budget too small for full bodies but enough for degraded form.
	out, sec := ClampDiff(sampleDiff, 200)
	if !strings.Contains(out, "diff --git") {
		t.Errorf("degraded output missing diff header")
	}
	if !strings.Contains(out, "@@ ") {
		t.Errorf("degraded output missing hunk header")
	}
	if sec.TruncationReason == "" {
		t.Errorf("expected non-empty TruncationReason")
	}
}

func TestClampDiffOmitsWhenNoRoom(t *testing.T) {
	out, sec := ClampDiff(sampleDiff, 5)
	if len(out) > 5+len(TruncationMarker) {
		t.Errorf("output exceeds budget by more than marker: %d", len(out))
	}
	_ = sec
}

== cli/internal/evidence/marker.go ==
package evidence

// TruncationMarker is the canonical string downstream parsers check for to
// detect that a section was clamped by an evidence primitive. Equality
// against this constant is the contract; do not redefine locally.
const TruncationMarker = "\n\n[…truncated by ddx evidence cap…]\n"

// Pre-dispatch overflow outcome classes (FEAT-022 §7, §12). These are the
// strings the reviewer and grader paths emit when bounded assembly still
// exceeds MaxPromptBytes.
const (
	OutcomeReviewContextOverflow  = "review-error: context_overflow"
	OutcomeCompareContextOverflow = "compare-error: context_overflow"
)

// Review-error taxonomy (FEAT-022 §12). The four classes the reviewer outcome
// event distinguishes. context_overflow is emitted by the pre-dispatch
// short-circuit (Stage C1); the remaining three classify post-dispatch
// failures. Operators triage on these literal strings, so they are part of
// the external contract.
const (
	OutcomeReviewProviderEmpty = "review-error: provider_empty"
	OutcomeReviewUnparseable   = "review-error: unparseable"
	OutcomeReviewTransport     = "review-error: transport"
)

== cli/internal/evidence/read.go ==
package evidence

import (
	"errors"
	"fmt"
	"io"
	"os"
)

// ErrOversize is returned by hard-fail readers (e.g. user-supplied prompt
// files, FEAT-022 §8). Callers compare with errors.Is to surface a
// distinct error class to the user.
var ErrOversize = errors.New("evidence: input exceeds cap")

// OversizeError carries the input-source name, observed size, and cap
// for actionable error messages (FEAT-022 Non-Functional / Failure mode
// clarity).
type OversizeError struct {
	Source        string
	ObservedBytes int64
	CapBytes      int
}

func (e *OversizeError) Error() string {
	return fmt.Sprintf("evidence: %s exceeds cap: observed %d bytes, cap %d bytes",
		e.Source, e.ObservedBytes, e.CapBytes)
}

func (e *OversizeError) Unwrap() error { return ErrOversize }

// ReadFileClamped reads up to max+1 bytes from path. If the file fits
// within max it returns (content, false, len(content), nil). If the file
// exceeds max it returns the first max bytes plus truncated=true and
// originalBytes set to the on-disk size (as observed via os.Stat). The
// implementation does not fully load oversize files into memory
// (FEAT-022 Non-Functional / Performance).
func ReadFileClamped(path string, max int) (content []byte, truncated bool, originalBytes int64, err error) {
	if max < 0 {
		return nil, false, 0, fmt.Errorf("evidence: negative cap %d", max)
	}
	// nolint:gosec // path is supplied by callers that have already validated it.
	f, err := os.Open(path)
	if err != nil {
		return nil, false, 0, err
	}
	defer f.Close()

	st, err := f.Stat()
	if err != nil {
		return nil, false, 0, err
	}
	originalBytes = st.Size()

	// Read max+1 bytes so we can detect overflow without loading the whole file.
	buf := make([]byte, max+1)
	n, readErr := io.ReadFull(f, buf)
	if readErr != nil && readErr != io.EOF && readErr != io.ErrUnexpectedEOF {
		return nil, false, originalBytes, readErr
	}

	if n > max {
		return buf[:max], true, originalBytes, nil
	}
	return buf[:n], false, int64(n), nil
}

// ReadFileHardFail reads path and returns *OversizeError (wrapping
// ErrOversize) if the file exceeds max. Used for user-supplied prompt
// files where silent truncation is forbidden (FEAT-022 §8).
func ReadFileHardFail(path string, max int, source string) ([]byte, error) {
	content, truncated, originalBytes, err := ReadFileClamped(path, max)
	if err != nil {
		return nil, err
	}
	if truncated {
		return nil, &OversizeError{
			Source:        source,
			ObservedBytes: originalBytes,
			CapBytes:      max,
		}
	}
	return content, nil
}

