				"recovery command %q must be exempt from the gate", name)
		})
	}
}

func writeProjectVersion(t *testing.T, workDir, version string) {
	t.Helper()
	require.NoError(t, os.MkdirAll(filepath.Join(workDir, ".ddx"), 0o755))
