	reviewSkipped := in.Reviewer == nil || in.NoReview
	if !reviewSkipped && HasBeadLabel(in.Bead.Labels, "review:skip") {
		reviewSkipped = HasBeadLabelPrefix(in.Bead.Labels, "review:skip-reason:")
	}

