// setupDocTestDir creates a temp directory with docgraph markdown documents.
func setupDocTestDir(t *testing.T) (dir string, docIDs []string) {
	t.Helper()
	dir = setupTestDir(t)

	docs := []struct {
		path    string
		id      string
		content string
	}{
		{
			path:    filepath.Join(dir, "docs", "alpha.md"),
			id:      "alpha",
