			id:      "beta",
			content: "---\nddx:\n  id: beta\n  depends_on:\n    - alpha\n---\n# Beta\n\nSecond document.\n",
		},
	}

	for _, d := range docs {
		if err := os.MkdirAll(filepath.Dir(d.path), 0o755); err != nil {
