		if got.Kind != chk.kind {
			t.Errorf("event[%d]: kind=%q want %q", i, got.Kind, chk.kind)
		}
		if got.Summary == nil || *got.Summary != chk.summary {
			t.Errorf("event[%d]: summary=%v want %q", i, got.Summary, chk.summary)
		}
	}
