		if err := store.AppendTurn(sessionID, turn); err != nil {
			t.Fatalf("AppendTurn() error = %v", err)
		}
	}
	want.Turns = turns

	got, err := store.Load(sessionID)
	if err != nil {
		t.Fatalf("Load() error = %v", err)
