// New creates a new DDx server bound to addr, serving data from workingDir.
func New(addr, workingDir string) *Server {
	nodeName := resolveNodeName()
	stateDir := serverAddrDir() // XDG-standard user-level dir, one per node
	state := loadServerState(stateDir, nodeName)
	state.workingDir = workingDir

	workers := NewWorkerManager(workingDir)
	workers.ReconcileStaleWorkers()
	beadHub := bead.NewWatcherHub(250 * time.Millisecond)
	csrfStore, err := ddxgraphql.NewStaticCSRFTokenStore()
	if err != nil {
		// CSRF token generation should never fail outside of a broken
		// crypto/rand. Fall back to a deterministic stub that rejects
		// every request rather than failing open.
		csrfStore = ddxgraphql.NewStaticCSRFTokenStoreWithToken("")
	}
	s := &Server{
		Addr:                               addr,
		WorkingDir:                         workingDir,
		mux:                                http.NewServeMux(),
		startTime:                          time.Now().UTC(),
		workers:                            workers,
		beadHub:                            beadHub,
		state:                              state,
		csrfTokens:                         csrfStore,
		operatorPromptIdempotency:          ddxgraphql.NewMemoryIdempotencyCache(),
		operatorPromptAutoApproveAllowlist: parseOperatorPromptAllowlistEnv(os.Getenv("DDX_OPERATOR_PROMPT_ALLOWLIST")),
		workerIngest:                       newWorkerIngestRegistry(workingDir),
	}
	s.reportedWorkers = newReportedWorkersAdapter(s.workerIngest)
	state.coordinatorReg = workers.LandCoordinators

	// Register the server's own project immediately.
	state.RegisterProject(workingDir)
	_ = state.save()

	s.routes()
	return s
}

// parseOperatorPromptAllowlistEnv parses a comma-separated identity list
// (DDX_OPERATOR_PROMPT_ALLOWLIST) into a normalized allowlist. Empty entries
// are skipped; whitespace is trimmed. The literal sentinel "localhost"
// matches any localhost-kind actor.
func parseOperatorPromptAllowlistEnv(raw string) []string {
	if raw = strings.TrimSpace(raw); raw == "" {
		return nil
	}
	parts := strings.Split(raw, ",")
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}

		baseDir, _ = os.Getwd()
	}

	worktrees := make([]string, len(runtime.Harnesses))
	if runtime.Sandbox {
		for i, harness := range runtime.Harnesses {
			label := harness
			if l, ok := runtime.ArmLabels[i]; ok {
				label = l
			}
			wt, err := createCompareWorktree(baseDir, id, label)
			if err != nil {
				record.Arms[i] = ComparisonArm{
					Harness:  label,
					ExitCode: 1,
					Error:    fmt.Sprintf("worktree: %s", err),
				}
				continue
			}
			worktrees[i] = wt
		}
	}

	var wg sync.WaitGroup
	for i, harness := range runtime.Harnesses {
		if runtime.Sandbox && worktrees[i] == "" && record.Arms[i].Error != "" {
			continue
		}
		wg.Add(1)
		go func(idx int, harnessName string) {
			defer wg.Done()
			record.Arms[idx] = runCompareArmWith(run, runtime, idx, harnessName, baseDir, prompt, worktrees[idx])
		}(i, harness)
	}
	wg.Wait()

	if runtime.Sandbox && !runtime.KeepSandbox {
		if cleanupSandbox != nil {
			cleanupSandbox(baseDir, id)
		} else {
			cleanupCompareWorktrees(baseDir, id)
		}
	}

	return record, nil
}

// defaultResolvePromptForCompare reads inline Prompt or PromptFile.
func defaultResolvePromptForCompare(runtime AgentRunRuntime) (string, error) {
	prompt := runtime.Prompt
	if runtime.PromptFile != "" {
		data, err := readPromptFileBounded(runtime.PromptFile)
		if err != nil {
			return "", fmt.Errorf("agent: read prompt file: %w", err)
		}
		prompt = string(data)
	}
	if prompt == "" {
		return "", fmt.Errorf("agent: prompt is required")
	}
	return prompt, nil
}

func runCompareArmWith(run RunFunc, runtime CompareRuntime, armIdx int, harnessName, baseDir, prompt, worktreePath string) ComparisonArm {
	label := harnessName
	if l, ok := runtime.ArmLabels[armIdx]; ok {
		label = l
	}
	arm := ComparisonArm{Harness: label}

	workDir := baseDir
	if worktreePath != "" {
		workDir = worktreePath
	}

	armRuntime := AgentRunRuntime{
		Prompt:          prompt,
		PromptSource:    runtime.PromptSource,
		Correlation:     runtime.Correlation,
		WorkDir:         workDir,
		HarnessOverride: harnessName,
	}
	if m, ok := runtime.ArmModels[armIdx]; ok {
		armRuntime.ModelOverride = m
	}

	result, err := run(armRuntime)
	if err != nil {
		arm.ExitCode = 1
		arm.Error = err.Error()
	} else {
		arm.Model = result.Model
		arm.Output = result.Output
		arm.ToolCalls = result.ToolCalls
		arm.Tokens = result.Tokens
		arm.InputTokens = result.InputTokens
		arm.OutputTokens = result.OutputTokens
		arm.CostUSD = result.CostUSD
		arm.DurationMS = result.DurationMS
		arm.ExitCode = result.ExitCode
		arm.Error = result.Error
	}

	if worktreePath != "" {
		arm.Diff = captureGitDiff(worktreePath)
	}

	if runtime.PostRun != "" && workDir != "" {
		out, ok := runPostCommand(workDir, runtime.PostRun)
		arm.PostRunOut = out
		arm.PostRunOK = &ok

