    96					BytesIncluded: len(content),
    97					BytesOmitted:  len(s.Content) - len(content),
    98					SelectedItems: []string{s.Name},
    99				}
   100				if reason != "" {
   101					section.TruncationReason = reason
   102				}
   103				res.Sections = append(res.Sections, section)
   104				continue
   105			}
   106			// Doesn't fit even at PerSectionCap — try line-trim to fit.
   107			if remaining > 0 {
   108				trimmed := trimToLineBudget(content, remaining-len(TruncationMarker))
   109				if trimmed != "" {
   110					body := trimmed + TruncationMarker
   111					used += len(body)
   112					res.Included = append(res.Included, SectionInput{
   113						Name: s.Name, Content: body,
   114					})
   115					res.Sections = append(res.Sections, EvidenceAssemblySection{
   116						Name:             s.Name,
   117						BytesIncluded:    len(body),
   118						BytesOmitted:     len(s.Content) - len(body),
   119						TruncationReason: "budget",
   120						SelectedItems:    []string{s.Name},
   121					})
   122					continue
   123				}
   124			}
   125			// No room: omit entirely.
   126			res.Omitted = append(res.Omitted, s)
   127			res.Sections = append(res.Sections, EvidenceAssemblySection{
   128				Name:             s.Name,
   129				BytesIncluded:    0,
   130				BytesOmitted:     len(s.Content),
   131				TruncationReason: "budget",
   132				OmittedItems:     []string{s.Name},
   133			})
   134		}
   135		res.TotalBytes = used
   136		return res
   137	}
   138	
   139	func capContent(s SectionInput) (string, string) {
   140		if s.PerSectionCap <= 0 || len(s.Content) <= s.PerSectionCap {
   141			return s.Content, ""
   142		}
   143		clamped, truncated, _ := ClampOutput(s.Content, s.PerSectionCap)
   144		if truncated {
   145			return clamped, "per_section_cap"
   146		}
   147		return clamped, ""
   148	}
   149	
   150	// trimToLineBudget returns the longest prefix of s, ending on a line
   151	// boundary, whose length is at most budget. Returns "" if budget <= 0
   152	// or the first line alone exceeds budget.
   153	func trimToLineBudget(s string, budget int) string {
   154		if budget <= 0 {
   155			return ""
   156		}
   157		if len(s) <= budget {
   158			return s
   159		}
   160		cut := strings.LastIndexByte(s[:budget], '\n')
   161		if cut <= 0 {
   162			return ""
   163		}
   164		return s[:cut+1]
   165	}

---
     1	package evidence
     2	
     3	import (
     4		"strings"
     5	)
     6	
     7	// InlineAssembly is the result of AssembleInline.
     8	type InlineAssembly struct {
     9		Prompt   string
    10		Sections []EvidenceAssemblySection
    11		// Overflow is true when, after all trimming, the assembled prompt
    12		// would still exceed total. Callers (reviewer/grader) MUST NOT
    13		// dispatch when Overflow is true (FEAT-022 §7) and should emit the
    14		// appropriate context_overflow outcome class instead.
    15		Overflow bool
    16	}
    17	
    18	// AssembleInline assembles a prompt by joining priority-ordered
    19	// sections under a total byte budget (FEAT-022 §2 inline-with-cap
    20	// strategy). Per-section caps and floor semantics are honored via the
    21	// SectionInput fields. Sections are joined verbatim with a single
    22	// newline separator between non-empty bodies.
    23	func AssembleInline(sections []SectionInput, total int) InlineAssembly {
    24		fit := FitSections(sections, total)
    25	
    26		var b strings.Builder
    27		for i, s := range fit.Included {
    28			if i > 0 {
    29				b.WriteByte('\n')
    30			}
    31			b.WriteString(s.Content)
    32		}
    33		out := b.String()
    34	
    35		overflow := len(out) > total
    36		return InlineAssembly{
    37			Prompt:   out,
    38			Sections: fit.Sections,
    39			Overflow: overflow,
    40		}
    41	}
